var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"휴가라니요? 당주님, 그게 갑자기 무슨 말씀이십니까?","JPN":"休み？　当主、突然どういうことですか？","ENG":"A vacation? My lady, what are you even talking about?","TWN":"休假？堂主，為何突然要我休假？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"치후유가 부상을 입은 채로 계속 검술수련을 하고 있었다고 나오님께 전해 들었어요.","JPN":"千冬が怪我をしたまま、ずっと剣術の修練をしていたとナオ様からお聞きしました。","ENG":"I heard from Miss Nao that you were training when your wounds are still open.","TWN":"我聽奈緒大人說你受傷還一直在練劍，"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"당주를 지켜야 할 호위가 회복에 전념하지 않고 밤새 검을 휘두른다는 것은 마음이 흔들린다는 것.","JPN":"当主を守るべき護衛が回復に専念せず徹夜で修練するというのは、心が揺れている証拠。","ENG":"A warrior wielding her sword instead of focusing on curing herself is a sign of an unstable heart.","TWN":"身為一個該保護堂主的護衛，不顧自己的身體熬夜練劍，就表示你的心在動搖。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그러니 내일 하루동안은 마음을 추스를 수 있도록 휴가를 다녀오세요.","JPN":"ですので、明日一日は心を整理できるよう、休みなさい。","ENG":"So please, take a day off tomorrow.","TWN":"所以你明天就好好休息一天，整理一下自己的思緒吧。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그럴 필요는 없습니다. 제가 아니면 누가 당주님을……!","JPN":"その必要はございません。私をおいて誰が当主を……！","ENG":"That won’t be necessary. If not for me, who will–","TWN":"我不需要，除了我還有誰可以保護……！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"걱정 마십시오. 자릴 비우신 동안 제가 목숨을 걸고 당주님을 지키겠습니다.","JPN":"ご心配は無用でございます。千冬様が席を外されている間、私が命をかけてご当主様をお守りいたします。","ENG":"Do not worry. I will protect Lady Nanahara with all my life.","TWN":"請放心，在您休假的這段期間，我會誓死保護堂主。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"……예?","JPN":"……はい？","ENG":"...Huh?","TWN":"……可是？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"치후유! 이건 당주의 명입니다! 하루동안 검에 대한 생각은 잊고 휴가를 다녀오세요!","JPN":"千冬！　これは当主の命令です！　一日、剣については考えず、休みなさい！","ENG":"Chifuyu! This is an order! Forget about training and take the day off tomorrow!","TWN":"千冬！這是堂主的命令！我命令你忘掉劍的事，放自己一天假！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"……에?","JPN":"……え？","ENG":"...Eh?","TWN":"……什麼？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHILDREN_EXTRA_NULL_NULL","text":{"KOREA":"저기 벤치 좀 봐. 예쁜 언니가 앉아있어.","JPN":"あのベンチ見て。キレイなお姉さんが座ってるよ。","ENG":"Look at the bench over there. The girl sitting on it is so pretty!","TWN":"你們看椅子那裡，有個漂亮姊姊坐在那。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHILDREN_EXTRA_NULL_NULL","text":{"KOREA":"뭔가 무서워 보이는 칼을 가지고 있어. 가까이 가지 말자.","JPN":"なんか怖そうな刀持ってる。近くに行かない方がいいね。","ENG":"She’s holding some kind of scary looking sword. We should keep our distance from her.","TWN":"她還帶著一把看起來很恐怖的刀欸，不要離她太近啦！"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"하아…….","JPN":"はあ……","ENG":"*Sigh...*","TWN":"哀哀……"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"당주님의 명이라고는 하나…… 휴가라는 걸 어찌 보내야 하는 것인지.","JPN":"当主の命令とはいえ……休みというものはどうやって過ごせばいいのだろう。","ENG":"Even if Lady Nanahara gave me orders... I don’t know how to spend free time.","TWN":"說是堂主的命令……但休假對我來說好陌生。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"……고작 30분이 지난 것인가?","JPN":"……やっと30分過ぎたのか？","ENG":"...Only 30 minutes passed?","TWN":"……才過30分鐘而已嗎？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GIRL_EXTRA_NULL_NULL","text":{"KOREA":"언니, 이거.","JPN":"お姉ちゃん、これあげる。","ENG":"Hi there.","TWN":"姊姊，這給你。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"……음? 초콜릿?","JPN":"……む？　チョコレート？","ENG":"...Hmm? Chocolate?","TWN":"……嗯？巧克力？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GIRL_EXTRA_NULL_NULL","text":{"KOREA":"우리 엄마가 그런 무기를 들고 있는 사람들은 도시를 지켜주는 훌륭한 사람들이랬어요.","JPN":"お姉ちゃんみたいに武器を持ってる人は都市を守ってくれる立派な人なんだって、ママから聞いたんだ。","ENG":"Mommy told me that people holding those kinds of weapons are people who keep the city safe.","TWN":"我媽媽說會帶著這種武器的人，都是保護城市的英雄。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GIRL_EXTRA_NULL_NULL","text":{"KOREA":"기운이 없어 보여. 맛있는 거 먹고 힘내요.","JPN":"元気が出ないの？　美味しいもの食べて頑張って。","ENG":"You look sad for somewhat reason. Eat this and cheer up!","TWN":"姊姊看起來好像沒什麼精神，吃點好吃的再繼續加油。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"고맙습니다, 소저.","JPN":"ありがとうございます、お嬢さん。","ENG":"Thank you, young lady.","TWN":"小妹妹，謝謝你。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"……여기에 앉아만 있어서야 사람들의 걱정만 끼칠 뿐, 그것이 당주님께서 바라시는 휴가는 아니겠죠.","JPN":"……ここに座っているばかりでは心配をかけるだけで、当主が願われる休みにはならないな。","ENG":"...Sitting here will only worry passersby. This is not how Lady Nanahara wanted me to spend my day off.","TWN":"……光是坐在這裡只會讓人擔心，這應該不是堂主希望的休假吧？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그렇다면……","JPN":"だとすると……","ENG":"That means...","TWN":"既然如此……"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"STUDENT_EXTRA_NULL_NULL","text":{"KOREA":"무슨 일이야? 애들이 왜 모여 있대?","JPN":"どうした？　何でみんな集まってるの？","ENG":"What’s going on? Why are people all gathered up?","TWN":"幹嘛幹嘛？大家在看什麼？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"STUDENT_EXTRA_NULL_NULL","text":{"KOREA":"학교 정문에 진지한 표정의 여고생 무사가 나타났대.","JPN":"学校の正門に真面目な顔した女子高生の武士が来てるんだって。","ENG":"There’s a solemn looking samurai girl in front of the main entrance.","TWN":"聽說學校正門有一個一臉嚴肅的女高中生武士。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"STUDENT_EXTRA_NULL_NULL","text":{"KOREA":"신고해야 하는 거 아냐? 칼을 든 여자애라며?","JPN":"通報した方がいいんじゃない？　剣を持った女の子なんでしょ？","ENG":"Did anyone call the police? She was holding a sword.","TWN":"要報警嗎？聽說她有帶刀欸？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"STUDENT_EXTRA_NULL_NULL","text":{"KOREA":"누굴 만나러 왔다던데, 사람이 많아서 잘 못 들었어.","JPN":"誰かに会いに来たらしいけど、人が多すぎてちゃんと聞こえなくてさ。","ENG":"I hear she’s here to see someone, but I couldn’t make out who.","TWN":"她好像是來找人的，人太多我聽不清楚。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"미나토, 방금 들었냐?","JPN":"湊、今の聞いたか？","ENG":"You hear that, Minato?","TWN":"南裕夏，你有聽到嗎？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"응.","JPN":"うん。","ENG":"Yeah.","TWN":"嗯。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"생각하고 있는 그 사람이겠지?","JPN":"あいつだろうな。","ENG":"Are you thinking of who I’m thinking?","TWN":"你有想到誰嗎？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"응…… 아마도.","JPN":"うん……多分。","ENG":"Yup... Probably.","TWN":"嗯……有吧。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L40_1","type":"dialog","speaker":"STUDENT_EXTRA_NULL_NULL","text":{"KOREA":"미나토! 너 학교 밖에서 무슨 짓을 저지르고 다니는 거야?","JPN":"湊！　お前、学校の外で何かやらかしたのか？","ENG":"Minato! What on earth do you do outside of school?","TWN":"南裕夏！你是不是在校外闖禍啦？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"STUDENT_EXTRA_NULL_NULL","text":{"KOREA":"교문 밖 사무라이가 너한테 대결을 신청했다는데?!","JPN":"校門の外の侍がお前に決闘を申し込んだらしいぜ！？","ENG":"The samurai outside the entrance asked for a duel with you.","TWN":"校門口有個武士說要找你對決欸？！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"……라고 해서 깜짝 놀랐지 뭐야? 아하하……","JPN":"……とか聞いてビックリしちゃったよ。あはは……","ENG":"...I was really shocked to hear that. Ah ha ha...","TWN":"……聽到有人這樣說害我嚇一跳，哈哈哈……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그렇습니까? 저는 나유카 공을 뵙고 싶다고 말씀드렸을 뿐입니다만.","JPN":"そうでしたか？　私は奈由香殿にお会いしたいと申し上げただけなのですが。","ENG":"Is that so? I merely asked to see you, Mr. Nayuka.","TWN":"是嗎？我只是說想找你而已。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"오해가 있었나 봐. 무기를 가지고 있는 게 학교에선 흔한 일은 아니니까.","JPN":"誤解されたみたいだね。学校で武器を持ってる人なんてあまりいないから。","ENG":"There must be some kind of a misunderstanding. It’s not common to carry around weapons in school.","TWN":"可能有什麼誤會吧？畢竟很少人會攜帶武器來學校。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"애초에 내가 어떻게 네 상대가 되겠어?","JPN":"だいたい、僕なんか君の相手にもならないよ。","ENG":"Besides, how could I ever win against you?","TWN":"而且我怎麼可能是你的對手？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그건, 그렇다고 생각하지 않습니다.","JPN":"そうは思いませんが。","ENG":"I do not think it is impossible.","TWN":"你別這麼說，我沒這麼想。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"제가 실례를 무릅쓰고 나유카 공을 찾아온 것도, 가르침을 얻고자 위함이니까요.","JPN":"失礼を承知で奈由香殿を訪ねたのも、教えを請うためですから。","ENG":"The reason why I came looking for you is to gain enlightenment, after all.","TWN":"我冒昧來找你，也是因為有事想請教你。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"나한테 배워? ……대체 뭘?","JPN":"僕に教えを？　……いったい何の？","ENG":"Enlightenment? ...What for?","TWN":"要請教我？……什麼事？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그날 나유카 공이 보여주셨던 선조의 힘. 그 힘을 발휘하신 경위에 대해 새겨듣고자 합니다.","JPN":"あの日奈由香殿が見せてくださったご先祖様の力。その力を発揮した経緯についてお聞きしたいのです。","ENG":"The ancestral powers that you have shown us that day... I wish to hear about how it happened.","TWN":"那天你不是有發揮出祖先的力量嗎？我想知道你是如何發揮出那股力量的。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그건 나도 잘 몰라. 그날 이후로 나도 그 힘은 한 번도 못 썼거든.","JPN":"それは僕もよくわからないな。あの日以来、あの力は一度も使えてないから。","ENG":"I don’t really know. I wasn’t able to use it again afterwards.","TWN":"我自己也不太清楚，那天之後我就再也沒用過那股力量。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그렇…… 습니까?","JPN":"そうなの……ですか？","ENG":"I... see...","TWN":"是……嗎？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그땐 어떻게든 해야 한다는 생각뿐이었고…… 딱히 선조의 목소리가 들렸다거나, 특별한 힘 같은 것도 느껴지지 않았어.","JPN":"あの時にはどうにかしなきゃっていう思いだけで……別にご先祖様の声が聞こえたとか、特別な力なんかも感じなかった。","ENG":"Back then, I was desperate to do something... I never heard any godly voices or felt a special surge of energy.","TWN":"那天我滿腦子只想著該怎麼辦……根本沒聽到什麼祖先的聲音，或是感受到什麼特別的力量。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"기대하고 찾아왔을 텐데…… 도움이 못돼서 미안하네.","JPN":"期待して来てくれたのに……役に立てなくてごめんね。","ENG":"I’m sorry to be of no help... It’s not what you were expecting, huh?","TWN":"你應該是想從我這裡得到什麼答案吧……很抱歉沒幫上忙。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"괜찮습니다. 크게 기대하지 않았으니까요.","JPN":"大丈夫です。別に期待してませんでしたから。","ENG":"No problem. I was not expecting much.","TWN":"沒關係，我本來就沒抱太大的期待。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"역시 그렇지? 하하……","JPN":"やっぱりそうだよね？　はは……","ENG":"Ha ha, I see...","TWN":"是喔？哈哈……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"하지만 바람의 목소리가 예견한 죽음을 나유카 공께서 뒤바꿨다는 사실은 분명합니다.","JPN":"ですが、風の声が予言した死を奈由香殿がひっくり返したという事実は変わりません。","ENG":"But the fact that you defied your destined fate that the voice of wind predicted does not change.","TWN":"不過有一件事是確定的，就是你扭轉了風聲預言的死亡。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"저 같은 것은 감히 엄두도 못 내던 일이죠.","JPN":"私ごときには思いもよらない出来事でした。","ENG":"It is something someone like me could never achieve.","TWN":"像我這種人是從來不敢想的。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"TEACHER_NPC_ARCHERY_NULL","text":{"KOREA":"여기에 있었구나, 미나토.","JPN":"ここにいたんだな、湊。","ENG":"There you are, Minato.","TWN":"原來你在這裡，南裕夏。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"선생님?","JPN":"先生？","ENG":"Teacher?","TWN":"老師？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"TEACHER_NPC_ARCHERY_NULL","text":{"KOREA":"빨리 요양원으로 가보는 게 좋을 것 같구나.","JPN":"早く老人ホームに行った方がいい。","ENG":"You should head towards the hospital soon.","TWN":"你趕快去一趟療養院，"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"TEACHER_NPC_ARCHERY_NULL","text":{"KOREA":"지금 할아버지가 많이 위독하신 모양이야.","JPN":"お祖父さんの具合がよくないらしいんだ。","ENG":"Your grandfather had a severe stroke.","TWN":"你爺爺現在好像病危中。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"할아버지……?","JPN":"お祖父様……？","ENG":"Grandfather...?","TWN":"爺爺……？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"네! 지금 바로 가보겠습니다!","JPN":"はい！　今すぐ行きます！","ENG":"I will do so right now!","TWN":"好！我馬上過去！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};